// ── Requirement translations keyed by req id ────────────────────

export const CRA_REQS_EN: ReqMap = {
  'A1-1': { name: 'No Known Vulnerabilities', gap: 'OTA signature verification missing, CVE tracking not formalized', evidence: 'OTA client accepts unsigned packages (cf. T-002). No documented CVE monitoring process. SBOM incomplete.', rationale: 'Partially fulfilled: HTTPS used for download (transport protection present), but without package integrity verification the requirement is not fully addressed. CVE monitoring missing as a process.', measure: 'Implement signed update process (Ed25519 or RSA-2048+), complete SBOM, establish weekly CVE monitoring', criteria: ['Firmware packages cryptographically verified before installation (e.g. Ed25519, RSA-2048+)', 'CVE monitoring process documented and executed at least weekly', 'SBOM in SPDX or CycloneDX format available and updated with each release'] },
  'A1-2': { name: 'Secure by Default', gap: 'Default password active, debug endpoint in production mode, SSH root login allowed', evidence: 'Login with admin/admin successful (cf. E-007). Debug endpoint /debug/env exposes credentials (cf. E-014). SSH root login allowed (cf. E-013). Port 1883 open in factory state.', rationale: 'Not fulfilled: Four independent secure-by-default violations. CRA requires products to expose no known attack vectors in factory state. Each violation alone would warrant a fail rating.', measure: '1. Force password change on first start (min. 12 characters, 3 of 4 complexity classes, blacklist top 10,000). 2. Disable debug endpoints in production (build flag). 3. SSH: PermitRootLogin=no, PasswordAuthentication=no, key-only. 4. Disable port 1883 by default, enable only 8883 (TLS).', criteria: ['First setup forces individual password creation (min. 12 chars, 3 of 4 complexity classes)', 'All debug endpoints disabled in production builds and not activatable via configuration', 'SSH root login disabled (PermitRootLogin=no), password auth disabled (PasswordAuthentication=no)', 'All non-essential ports and services disabled in factory state'] },
  'A1-3': { name: 'Protection Against Unauthorized Access', gap: 'No MFA, weak session management, expired tokens not revoked', evidence: 'Session cookies without Secure/HttpOnly flags (cf. E-008). Expired API tokens accepted (cf. S-009). No MFA available. API endpoints without RBAC.', rationale: 'Not fulfilled: Four independent vulnerabilities affect this requirement. Access control is deficient at multiple levels (Web UI, API, token management).', measure: '1. Implement MFA for admin (TOTP via Google Authenticator/Authy or FIDO2 WebAuthn). 2. Session cookies: Secure=true, HttpOnly=true, SameSite=Strict; token rotation after login; timeout ≤ 30 min. 3. Automate token revocation on offboarding (HR webhook → API). 4. RBAC at endpoint level with permission matrix.', criteria: ['MFA implemented for all administrative access (TOTP or FIDO2)', 'Session cookies with Secure, HttpOnly and SameSite flags; token rotation after login; timeout ≤ 30 min', 'Automated token revocation on employee offboarding', 'RBAC at API endpoint level with documented permission model'] },
  'A1-4': { name: 'Data Confidentiality', gap: 'MQTT on port 1883 unencrypted, OPC-UA Security Mode None', evidence: 'Wireshark capture confirms plaintext transmission on port 1883 (cf. I-005). OPC-UA client configured with SecurityMode=None (cf. I-011). REST API properly secured via HTTPS.', rationale: 'Partially fulfilled: REST API communication over TLS correctly implemented. However, MQTT and OPC-UA communication unencrypted — critical in industrial environments as control data and process secrets are affected.', measure: '1. MQTT exclusively over TLS 1.2+ (port 8883), disable port 1883 in firewall rules and configuration. 2. OPC-UA: SecurityMode=SignAndEncrypt, SecurityPolicy=Basic256Sha256. 3. Enable mutual TLS (mTLS) for client authentication.', criteria: ['All MQTT communication encrypted via TLS 1.2+ (port 8883)', 'Port 1883 disabled and not configurable', 'OPC-UA SecurityMode=SignAndEncrypt with Basic256Sha256', 'TLS certificate validation active on client and server side'] },
  'A1-5': { name: 'Data Integrity', gap: '', evidence: 'REST API uses TLS 1.3 with HMAC integrity checks. Firmware images distributed with SHA-256 checksums. Database transactions use ACID guarantees. Configuration changes performed atomically.', rationale: 'Fulfilled: Data integrity is ensured at transport level (TLS), storage level (ACID) and for firmware distribution (SHA-256). Only exception is the missing signature check for OTA (assessed separately under A1-1).' },
  'A1-6': { name: 'Data Source Authenticity', gap: '', evidence: 'REST API clients authenticate via JWT tokens with RS256. MQTT clients use individual credentials (username/password). OPC-UA server identified via X.509 certificate. Firmware download from authenticated update server (HTTPS).', rationale: 'Fulfilled: Data sources are authenticated on all communication channels. JWT token verification with asymmetric cryptography. Limitation: MQTT auth is username/password-based, not certificate-based — acceptable for Class II.' },
  'A1-7': { name: 'Availability & Resilience', gap: 'No rate limiting on MQTT broker and REST API', evidence: 'Load test: Broker failure at 500 concurrent connections (cf. D-006). REST API without rate limiting (cf. D-012). Watchdog process for MQTT broker exists, but auto-restart takes > 60s.', rationale: 'Partially fulfilled: Basic availability given, watchdog implemented. But no protection against targeted overload. Recovery time (> 60s) too long for industrial environments.', measure: '1. Rate limiting per client IP on MQTT (max. 50 connections/min) and REST (max. 100 requests/min). 2. Connection throttling with configurable maximum (e.g. max_clients=200). 3. Optimize watchdog recovery to < 10s (systemd Restart=always, RestartSec=3).', criteria: ['Rate limiting per client IP configured (max connections/minute)', 'Connection throttling limits concurrent connections to defined threshold', 'Watchdog process auto-restarts broker on failure (< 10s recovery)'] },
  'A1-8': { name: 'Security Logging & Monitoring', gap: 'Admin actions not logged, no SIEM export', evidence: 'System check: No log files for administrative actions (cf. R-004). No syslog export. No tamper protection for logs. System logs only on local partition without rotation.', rationale: 'Not fulfilled: Without logging, traceability of security incidents is impossible. Forensic analysis after an incident is excluded. Violation of CRA Art. 10 Para. 10.', measure: '1. Implement audit log for all admin actions (JSON format: ISO-8601 timestamp, user ID, action, before/after value, source IP). 2. Log rotation (logrotate, max. 90 days) and tamper protection (append-only via chattr +a). 3. Configurable syslog/SIEM export (rsyslog → TCP 514, TLS-secured).', criteria: ['All administrative actions logged with timestamp, user ID and action', 'Logs protected against manipulation (append-only or signed)', 'Log export to external system (syslog/SIEM) configurable and documented'] },
  'A2-1': { name: 'Vulnerability Identification', gap: 'Ad-hoc process exists but not documented or regular', evidence: 'Interview: Development team fixes vulnerabilities reactively. Last pentest results > 14 months old. No SAST/DAST in CI/CD pipeline. Ad-hoc reviews for critical releases.', rationale: 'Partially fulfilled: Vulnerabilities are fixed reactively — awareness exists. But CRA requires a systematic, documented process with regular tests.', measure: '1. Document vulnerability management process per ISO/IEC 30111 (roles, responsibilities, escalation). 2. Integrate SAST (e.g. SonarQube, Semgrep) and DAST (e.g. ZAP, Nuclei) into CI/CD. 3. Annual pentests by external auditors (e.g. BSI-certified body).', criteria: ['Documented vulnerability handling process per ISO/IEC 30111', 'SAST and DAST integrated in CI/CD pipeline and executed on every build', 'Annual penetration test by external provider, report documented'] },
  'A2-2': { name: 'Vulnerability Tracking', gap: '', evidence: 'Jira-based vulnerability tracking active. All identified vulnerabilities recorded as security issues with severity, status and assigned owner. Dashboard with open security issues available.', rationale: 'Fulfilled: Systematic tracking via ticketing system. Vulnerabilities categorized, prioritized and tracked. SLA for Critical (48h) and High (7 days) defined.' },
  'A2-3': { name: 'Patch Management Process', gap: '', evidence: 'Documented patch management process in place. Monthly patch cycles for non-critical, emergency patches within 48h for critical. CI/CD pipeline automates build and deployment. Rollback mechanism tested.', rationale: 'Fulfilled: Structured patch process with defined SLAs, automated pipeline and tested rollback. Process practiced for 18 months.' },
  'A2-4': { name: 'Coordinated Vulnerability Disclosure', gap: '', evidence: 'security.txt published on website with PGP key and contact email. Coordinated disclosure policy documented (90-day window). Incoming vulnerability reports tracked in Jira and acknowledged within 72h.', rationale: 'Fulfilled: Disclosure process is published, reachable and actively used. Last external report correctly acknowledged within 72h and resolved within 45 days.' },
  'A2-5': { name: 'Security Updates After Vulnerability Discovery', gap: '', evidence: 'Update mechanism (OTA) functional. Security updates released separately from feature updates. Customers notified via email advisory. Update availability within 7 days of vulnerability confirmation.', rationale: 'Fulfilled: Security updates delivered promptly. Separate security update channel avoids delays from feature releases. Limitation: OTA signature check missing (separately under A1-1).' },
  'A2-6': { name: 'Retroactive Patches (Older Versions)', gap: 'Only current major version is patched', evidence: 'Interview: Only current major version (3.x) receives security patches. Version 2.x (still deployed at 30% of customers) is no longer patched. No documented end-of-support schedule.', rationale: 'Partially fulfilled: Current version is patched. But 30% of the installation base without security updates violates the CRA lifecycle support principle.', measure: '1. Document end-of-support policy and publish on website. 2. Provide security-critical patches for v2.x for at least 12 months. 3. Simplify upgrade path from v2.x to v3.x (migration tool).', criteria: ['End-of-support policy published with clear timelines per version', 'Security-critical patches for n-1 major version for at least 12 months after successor release', 'Documented and tested upgrade path between major versions'] },
  'A2-7': { name: 'Vulnerability Lifecycle Logging', gap: '', evidence: 'Jira workflow for security issues: Open → Confirmed → In Progress → Resolved → Verified → Closed. All status changes automatically logged with timestamp and assignee. Reports exportable.', rationale: 'Fulfilled: Complete lifecycle log for each vulnerability. Audit trail traceable. Reports available for internal and external audits.' },
  'A2-8': { name: 'SBOM', gap: 'No complete SBOM available', evidence: 'Document review: Partial SBOM present (direct dependencies). Transitive dependencies not captured. No standardized format (neither SPDX nor CycloneDX). Manual maintenance, not CI/CD integrated.', rationale: 'Not fulfilled: CRA requires a machine-readable SBOM with all components. Current SBOM is incomplete, non-standardized and not automated.', measure: '1. Integrate SBOM generation into CI/CD (Syft for containers, Trivy for OS packages). 2. Output format: CycloneDX 1.5 (JSON). 3. Include transitive dependencies. 4. Auto-generate on each release and publish as build artifact.', criteria: ['SBOM in SPDX or CycloneDX format machine-readable', 'SBOM auto-generated on each release (CI/CD integration)', 'All direct and transitive dependencies captured with version and license'] },
  'A2-9': { name: 'Transparency Reports', gap: '', evidence: 'Product security data sheet published. Release notes include security-relevant changes. Quarterly security report distributed to customers. All public advisories archived on website.', rationale: 'Fulfilled: Transparency on security properties and known vulnerabilities ensured. Regular communication to customers established.' },
  'Art10': { name: 'Cybersecurity Across the Lifecycle', gap: 'Secure SDLC framework not formalized, no end-to-end governance', evidence: 'Cybersecurity integrated in SDLC: threat modeling in design phase, SAST in development, pentest before release, monitoring in operations. Security champion appointed. Annual security training for developers. However: no formalized secure SDLC framework (e.g. BSIMM, SAMM). Governance structures (security board, risk acceptance process) missing.', rationale: 'Partially fulfilled: Practical security activities exist. However CRA Art. 10 requires documented governance structure for cybersecurity across the entire product lifecycle — not just technical measures but organizational processes, responsibilities and escalation paths.', measure: '1. Formalize secure SDLC framework (BSIMM or OWASP SAMM as basis). 2. Establish security governance board (quarterly reviews). 3. Document risk acceptance process (criteria, approval levels, documentation requirements).', criteria: ['Formalized secure SDLC framework documented and actively used', 'Security governance board with regular reviews established', 'Risk acceptance process with defined approval levels documented'] },
  'Art11': { name: 'Cybersecurity Testing & Certification', gap: 'Testing framework not formalized, no external certification', evidence: 'Unit tests for security functions present. SAST tool in CI/CD. But: no formalized security testing framework. No external certification or accredited audit performed. Test coverage for security functions at ~65%.', rationale: 'Partially fulfilled: Security tests exist but not in a formalized framework. External certification for Class II may be required — not yet addressed.', measure: '1. Formalize security testing framework (OWASP ASVS Level 2 as basis). 2. Increase test coverage for security functions to > 85%. 3. Commission external conformity assessment per CRA Art. 24.', criteria: ['Formalized security testing framework based on OWASP ASVS or equivalent', 'Test coverage for security functions ≥ 85%', 'External conformity assessment per CRA Art. 24 performed or commissioned'] },
  'Art13': { name: 'Technical Documentation', gap: 'Incomplete architecture documentation, no formal risk analysis', evidence: 'Architecture diagram present but incomplete (MQTT and Modbus interfaces missing). No documented risk analysis per Annex VII. User manual present and current.', rationale: 'Partially fulfilled: Basic documentation exists. However Annex VII requirements (complete technical documentation including risk analysis) are not addressed.', measure: '1. Complete architecture documentation (all interfaces, data flows, security zones). 2. Create formal risk analysis per Annex VII (based on this STRIDE assessment). 3. Prepare EU declaration of conformity per Art. 28.', criteria: ['Complete system description including all interfaces and data flows', 'Documented risk analysis per CRA Annex VII', 'EU declaration of conformity per Art. 28 prepared'] },
  'Art14': { name: 'Reporting Obligations (24h/72h)', gap: 'No incident response process, no ENISA reporting route', evidence: 'Interview: No documented IR process. CRA Art. 14 reporting obligations unknown to development team. No ENISA account registered. No dry run conducted.', rationale: 'Not fulfilled: CRA Art. 14 requires reporting actively exploited vulnerabilities within 24h (early warning) and 72h (full report) to ENISA. Without a prepared process, meeting these deadlines is impossible.', measure: '1. Document IR process (roles: IR lead, communications, technical; escalation levels: Sev1/2/3; timeframes: 24h/72h). 2. Register on ENISA reporting platform and test access. 3. Conduct tabletop exercise with realistic scenario. 4. Set up on-call rotation for security incidents (PagerDuty/Opsgenie).', criteria: ['Incident response process documented with defined roles, escalation levels and timeframes', 'ENISA reporting platform registered and reporting process tested (dry run)', 'Early warning within 24h and full report within 72h ensured', 'On-call rotation for security incidents defined'] },
  'Art15': { name: 'Conformity Assessment Procedure', gap: 'No defined conformity path, self-assessment vs. notified body not determined', evidence: 'Product classified as "Default Class". No documented justification why the product is not classified as "critical product" (Class I or II). No conformity assessment procedure defined.', rationale: 'Partially fulfilled: CRA Art. 15 requires an appropriate conformity assessment procedure. The choice depends on product classification. Without documented classification justification and defined conformity path, this requirement is not fully addressed.', measure: '1. Document and justify product classification (Default vs. Class I/II per CRA Annex III/IV). 2. Define conformity assessment procedure (Module A for Default, Module B+C for Class II). 3. For Class II: identify and engage notified body.', criteria: ['Product classification documented with justification (comparison with CRA Annex III and IV)', 'Conformity assessment procedure defined and documented', 'For Class II: notified body identified'] },
  'Art16': { name: 'EU Declaration of Conformity', gap: 'Draft version available but not finalized and incomplete', evidence: 'EU declaration of conformity in draft form. Content does not cover all mandatory information per CRA Annex V (missing: reference to applied harmonized standards, conformity assessment procedure indication, authorized representative signature).', rationale: 'Partially fulfilled: Approach exists, but the declaration is neither complete in content nor formally signed. CRA Art. 16 requires a complete EU declaration of conformity per Annex V before placing on the market.', measure: '1. Complete declaration per CRA Annex V. 2. Add references to applied standards (ETSI EN 303 645, ISO 27001). 3. Reference conformity assessment procedure. 4. Prepare signature by authorized representative.', criteria: ['EU declaration of conformity contains all mandatory information per CRA Annex V', 'References to applied harmonized standards documented', 'Conformity assessment procedure referenced', 'Signed by designated authorized representative'] },
  'Art17': { name: 'Post-Market Surveillance', gap: 'No post-market surveillance process implemented', evidence: 'Interview: No documented post-market surveillance process. No systematic capture of field data on security incidents. No process for evaluating new threats after market launch. Customer feedback handled ad hoc.', rationale: 'Not fulfilled: CRA requires active monitoring of the product after placing on the market. The manufacturer must identify new vulnerabilities, provide security updates and take corrective measures when necessary. Without a systematic process this obligation cannot be met.', measure: '1. Document post-market surveillance plan (data sources: CVE feeds, customer reports, telemetry). 2. Regular threat intelligence evaluation (monthly). 3. Define escalation criteria for corrective measures. 4. Annual security re-assessment of the product.', criteria: ['Post-market surveillance plan documented and implemented', 'Threat intelligence feeds actively monitored (CVE, NVD, vendor advisories)', 'Escalation criteria for security incidents defined', 'Annual security re-assessment planned'] },
};

